import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.BRHnm6VC.js";const p=JSON.parse('{"title":"Grade 10 Information Technology — Theory Study Notes","description":"","frontmatter":{},"headers":[],"relativePath":"exam-preparation/Grade_10_IT_Theory_Notes.md","filePath":"exam-preparation/Grade_10_IT_Theory_Notes.md"}'),s={name:"exam-preparation/Grade_10_IT_Theory_Notes.md"};function r(i,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="grade-10-information-technology-—-theory-study-notes" tabindex="-1">Grade 10 Information Technology — Theory Study Notes <a class="header-anchor" href="#grade-10-information-technology-—-theory-study-notes" aria-label="Permalink to &quot;Grade 10 Information Technology — Theory Study Notes&quot;">​</a></h1><p><em>A topic-by-topic reference for CAPS Information Technology theory.</em></p><p>These notes follow the CAPS topic order: System Technologies → Communication and Network Technologies → Data and Information Management → Solution Development. Each topic is explained in full so the notes can be used as standalone study material for any examination.</p><hr><h1 id="section-1-system-technologies" tabindex="-1">SECTION 1: SYSTEM TECHNOLOGIES <a class="header-anchor" href="#section-1-system-technologies" aria-label="Permalink to &quot;SECTION 1: SYSTEM TECHNOLOGIES&quot;">​</a></h1><h2 id="_1-1-computing-devices" tabindex="-1">1.1 Computing Devices <a class="header-anchor" href="#_1-1-computing-devices" aria-label="Permalink to &quot;1.1 Computing Devices&quot;">​</a></h2><p>A <strong>computing device</strong> is any electronic device that can accept input, process data according to a set of instructions, store data, and produce output. The word &quot;computer&quot; no longer refers only to a desktop PC — it includes laptops, tablets, smartphones, smartwatches, gaming consoles, smart TVs, and even devices like ATMs and modern motor vehicles.</p><h3 id="convergence-devices" tabindex="-1">Convergence devices <a class="header-anchor" href="#convergence-devices" aria-label="Permalink to &quot;Convergence devices&quot;">​</a></h3><p>A <strong>convergence device</strong> is a single device that combines the functions of several separate devices into one. The clearest example is the modern smartphone: a single device that replaces a telephone, camera, video camera, calculator, music player, alarm clock, GPS, web browser, gaming console and torch. Other examples include smart TVs (TV + internet browser + streaming platform) and modern game consoles (gaming + streaming + web browser + media player).</p><h3 id="advantages-and-disadvantages-of-using-computers" tabindex="-1">Advantages and disadvantages of using computers <a class="header-anchor" href="#advantages-and-disadvantages-of-using-computers" aria-label="Permalink to &quot;Advantages and disadvantages of using computers&quot;">​</a></h3><p>Computers have transformed how people work, learn and communicate, but the benefits come with costs.</p><p>Advantages include faster processing of large amounts of data, accurate calculations, the ability to store and quickly retrieve enormous amounts of information, easy global communication, and the automation of repetitive tasks so that people can focus on more creative work.</p><p>Disadvantages include the high cost of equipment and software, the dependency that develops (when systems fail, work stops completely), health issues from prolonged use such as eye strain and repetitive strain injuries, the loss of jobs through automation, increased exposure to cybercrime, and the social impact of reduced face-to-face interaction.</p><h2 id="_1-2-hardware" tabindex="-1">1.2 Hardware <a class="header-anchor" href="#_1-2-hardware" aria-label="Permalink to &quot;1.2 Hardware&quot;">​</a></h2><h3 id="input-and-output-devices" tabindex="-1">Input and output devices <a class="header-anchor" href="#input-and-output-devices" aria-label="Permalink to &quot;Input and output devices&quot;">​</a></h3><p>An <strong>input device</strong> allows the user (or the environment) to give data and instructions to the computer. Common examples are the keyboard, mouse, touchscreen, microphone, webcam, scanner and barcode reader.</p><p>An <strong>output device</strong> is used by the computer to present information to the user. Common examples are the monitor, printer, speakers and headphones.</p><p>Some devices are both input and output — a touchscreen, for example, displays output (it is a monitor) but also accepts input (you tap on it). A modem and a network card are also both input and output devices because they send and receive data.</p><h3 id="storage-—-hdd-vs-ssd" tabindex="-1">Storage — HDD vs SSD <a class="header-anchor" href="#storage-—-hdd-vs-ssd" aria-label="Permalink to &quot;Storage — HDD vs SSD&quot;">​</a></h3><p>Both an HDD (Hard Disk Drive) and an SSD (Solid State Drive) are used as <strong>secondary storage</strong> — they hold data permanently, even when the computer is switched off. The difference is in how they store data:</p><ul><li>An <strong>HDD</strong> uses spinning magnetic platters and a moving read/write head, much like an old vinyl record player. Because it has moving mechanical parts, it is slower, makes a small amount of noise, generates heat, uses more power, and is more easily damaged by being knocked or dropped.</li><li>An <strong>SSD</strong> uses flash memory chips with no moving parts at all. It is much faster (boot times and program loading drop dramatically), silent, more energy-efficient, lighter, more resistant to physical shock, but is more expensive per gigabyte.</li></ul><h3 id="monitors-—-lcd-and-led" tabindex="-1">Monitors — LCD and LED <a class="header-anchor" href="#monitors-—-lcd-and-led" aria-label="Permalink to &quot;Monitors — LCD and LED&quot;">​</a></h3><p>An LCD (Liquid Crystal Display) monitor uses fluorescent (CCFL) backlighting behind the liquid crystal panel. An LED (Light Emitting Diode) monitor uses LEDs as the backlight instead.</p><p>Advantages of LED over LCD include lower power consumption, a thinner and lighter design, longer lifespan, better contrast and brighter colours, and a more environmentally friendly manufacturing process (no mercury in the backlight).</p><p><strong>Screen size</strong> is measured <strong>diagonally from corner to corner of the visible screen</strong>. A &quot;17.3 inch&quot; monitor means the diagonal distance across the screen is 17.3 inches (about 44 cm). Screen size is not the same as resolution — a small screen can have a very high resolution, and a large screen can have a low resolution.</p><h3 id="barcode-scanners" tabindex="-1">Barcode scanners <a class="header-anchor" href="#barcode-scanners" aria-label="Permalink to &quot;Barcode scanners&quot;">​</a></h3><p>A <strong>barcode scanner</strong> is an input device that reads the parallel black-and-white lines printed on product labels, book covers, packages and many other items. It works by shining a light onto the barcode and measuring the reflection — the white spaces reflect more light than the black bars. The scanner converts this pattern into the number the barcode represents and sends that number to the computer.</p><p>Benefits of using barcode scanners include:</p><ul><li>Speed — scanning is much faster than typing a long product/identification number.</li><li>Accuracy — there are no typing errors, so the wrong item is never recorded.</li><li>Automation — once an item is scanned, the database can be updated immediately (e.g. stock count reduced, item marked as sold, or item marked as out on loan).</li></ul><h3 id="upgrading-for-performance" tabindex="-1">Upgrading for performance <a class="header-anchor" href="#upgrading-for-performance" aria-label="Permalink to &quot;Upgrading for performance&quot;">​</a></h3><p>When a computer is slow at running many programs at the same time, the component to upgrade is usually the <strong>RAM</strong>. RAM is the working memory where all open programs and their data must sit while the CPU uses them. If there is not enough RAM, the operating system has to swap data constantly between RAM and the (much slower) storage drive, which causes the computer to feel sluggish.</p><h3 id="webcams-and-video-conferencing" tabindex="-1">Webcams and video conferencing <a class="header-anchor" href="#webcams-and-video-conferencing" aria-label="Permalink to &quot;Webcams and video conferencing&quot;">​</a></h3><p>Most modern laptops have a small <strong>webcam</strong> built into the top of the screen bezel, together with a microphone. The webcam captures video and the microphone captures audio, which together allow the laptop to be used for video conferencing (Zoom, Microsoft Teams, Google Meet) without buying any extra hardware.</p><h2 id="_1-3-system-software-and-the-operating-system" tabindex="-1">1.3 System Software and the Operating System <a class="header-anchor" href="#_1-3-system-software-and-the-operating-system" aria-label="Permalink to &quot;1.3 System Software and the Operating System&quot;">​</a></h2><h3 id="what-system-software-is" tabindex="-1">What system software is <a class="header-anchor" href="#what-system-software-is" aria-label="Permalink to &quot;What system software is&quot;">​</a></h3><p><strong>System software</strong> is the software that controls and manages the computer&#39;s hardware so that the user and application software (like Word or Chrome) can actually use it. It is the &quot;middleman&quot; between the hardware and the application programs.</p><p>System software includes:</p><ul><li>the <strong>operating system</strong> (e.g. Windows 11, macOS, Linux, Android)</li><li><strong>utility programs</strong> (antivirus, disk defragmenter, file compression, backup tools)</li><li><strong>device drivers</strong></li></ul><p>Examples of operating systems include Windows 11, macOS, Linux distributions like Ubuntu, Android (for phones) and iOS (for iPhones). Microsoft Word, Google Chrome and Adobe Photoshop are <em>not</em> operating systems — they are application software that runs on top of the operating system.</p><h3 id="the-purpose-of-the-operating-system" tabindex="-1">The purpose of the operating system <a class="header-anchor" href="#the-purpose-of-the-operating-system" aria-label="Permalink to &quot;The purpose of the operating system&quot;">​</a></h3><p>The main purpose of an operating system is to <strong>manage the hardware and software resources of the computer</strong>. This includes:</p><ul><li>providing a user interface so the user can interact with the computer</li><li>managing memory (deciding which programs get RAM and how much)</li><li>managing the CPU (scheduling which program runs when)</li><li>managing storage (organising the file system)</li><li>managing input and output devices</li><li>providing security (user accounts, passwords, permissions)</li></ul><h3 id="device-drivers" tabindex="-1">Device drivers <a class="header-anchor" href="#device-drivers" aria-label="Permalink to &quot;Device drivers&quot;">​</a></h3><p>A <strong>device driver</strong> is a small program that allows the operating system to communicate with a specific hardware device. Each device that the computer connects to (printer, scanner, graphics card, webcam, etc.) needs its own driver because each manufacturer designs its hardware slightly differently.</p><p>Device drivers are important because without the correct driver, the operating system simply does not know how to &quot;talk to&quot; the hardware. The device might be physically connected and powered on, but it will not work. A printer is a typical example — even though it is plugged in, it will not print until the driver is installed.</p><h3 id="plug-and-play-and-hot-swappable-devices" tabindex="-1">Plug-and-Play and hot-swappable devices <a class="header-anchor" href="#plug-and-play-and-hot-swappable-devices" aria-label="Permalink to &quot;Plug-and-Play and hot-swappable devices&quot;">​</a></h3><p><strong>Plug-and-Play (PnP)</strong> is a technology that allows the operating system to automatically detect a new hardware device when it is connected, identify it, and load the correct driver — all without the user needing to manually install anything. A printer that &quot;just works&quot; the moment you plug it in is using Plug-and-Play.</p><p>The advantage is that the user does not need any technical knowledge to add new hardware. The device is ready to use within seconds.</p><p>A <strong>hot-swappable</strong> device is one that can be safely connected to (or disconnected from) the computer while the computer is switched on and running. A USB flash drive is the classic example — you can plug it in and pull it out without restarting. Older technologies were <em>not</em> hot-swappable — adding a hard drive used to require shutting the machine down completely first.</p><h2 id="_1-4-proprietary-vs-open-source-software" tabindex="-1">1.4 Proprietary vs Open-Source Software <a class="header-anchor" href="#_1-4-proprietary-vs-open-source-software" aria-label="Permalink to &quot;1.4 Proprietary vs Open-Source Software&quot;">​</a></h2><p>When choosing software, users have to decide between <strong>proprietary software</strong> and <strong>open-source software</strong>.</p><ul><li><strong>Proprietary software</strong> (e.g. Microsoft Office, Adobe Photoshop) is owned by a company. Users must pay for a licence to use it. The source code is kept secret and may not be changed by the user.</li><li><strong>Open-source software</strong> (e.g. LibreOffice, Linux, GIMP) is software whose source code is freely available. Anyone may use, copy, study and modify the code. It is usually free of charge.</li></ul><p><strong>Comparison of support:</strong></p><ul><li>Proprietary software comes with <strong>official paid support</strong> from the company that makes it — phone help desks, online ticket systems, official documentation. The support is usually reliable and professional, but is part of what you pay for.</li><li>Open-source software relies mainly on <strong>community support</strong> — online forums, user groups, wikis and volunteers. Help is free but can be slow and inconsistent. Some open-source projects offer paid commercial support as an add-on.</li></ul><hr><h1 id="section-2-communication-and-network-technologies" tabindex="-1">SECTION 2: COMMUNICATION AND NETWORK TECHNOLOGIES <a class="header-anchor" href="#section-2-communication-and-network-technologies" aria-label="Permalink to &quot;SECTION 2: COMMUNICATION AND NETWORK TECHNOLOGIES&quot;">​</a></h1><h2 id="_2-1-computer-networks" tabindex="-1">2.1 Computer Networks <a class="header-anchor" href="#_2-1-computer-networks" aria-label="Permalink to &quot;2.1 Computer Networks&quot;">​</a></h2><p>A <strong>computer network</strong> is a group of two or more computing devices that are connected together so that they can share data, resources (like printers and storage) and an internet connection.</p><p><strong>Communication media</strong> is the physical or wireless pathway that the data travels along. Examples of wired media include UTP (twisted-pair copper) cables, coaxial cables and fibre-optic cables. The most common wireless medium is Wi-Fi, which uses radio waves; others include Bluetooth, infrared and cellular (3G/4G/5G).</p><h3 id="advantages-of-using-a-computer-network" tabindex="-1">Advantages of using a computer network <a class="header-anchor" href="#advantages-of-using-a-computer-network" aria-label="Permalink to &quot;Advantages of using a computer network&quot;">​</a></h3><ul><li><strong>Sharing of resources</strong> — many users can share one printer, one internet connection, one set of files, instead of each computer needing its own.</li><li><strong>Communication</strong> — users can send each other messages, emails, files and video calls easily.</li><li><strong>Centralised data</strong> — files can be stored in one central location, making backup and access easier.</li><li><strong>Cost saving</strong> — sharing one printer between 30 computers is much cheaper than buying 30 printers.</li></ul><h3 id="lan-vs-wan" tabindex="-1">LAN vs WAN <a class="header-anchor" href="#lan-vs-wan" aria-label="Permalink to &quot;LAN vs WAN&quot;">​</a></h3><p>A <strong>LAN (Local Area Network)</strong> is a network that covers a small geographic area, typically a single building or campus. The network in a school, in an office or in a home is a LAN. The owner of the network usually owns all the cables and equipment.</p><p>A <strong>WAN (Wide Area Network)</strong> is a network that covers a large geographic area, often connecting many LANs together across cities, countries or continents. The internet is the largest WAN in the world. A WAN typically uses cables, equipment and services that are owned and rented from telecommunications companies.</p><p>The network used <strong>within a school building</strong> is a LAN.</p><h2 id="_2-2-network-hardware" tabindex="-1">2.2 Network Hardware <a class="header-anchor" href="#_2-2-network-hardware" aria-label="Permalink to &quot;2.2 Network Hardware&quot;">​</a></h2><h3 id="routers" tabindex="-1">Routers <a class="header-anchor" href="#routers" aria-label="Permalink to &quot;Routers&quot;">​</a></h3><p>A <strong>router</strong> is a network device that connects two or more networks and routes (directs) data packets between them. In a typical home or school, the router connects the local network (LAN) to the internet (WAN). It looks at the address of every data packet and decides which network and which device it must be sent to.</p><h3 id="functions-of-network-communication" tabindex="-1">Functions of network communication <a class="header-anchor" href="#functions-of-network-communication" aria-label="Permalink to &quot;Functions of network communication&quot;">​</a></h3><p>Network communication exists to allow:</p><ul><li><strong>Resource sharing</strong> — printers, storage and internet connections can be used by many devices.</li><li><strong>Data sharing</strong> — files and information can be sent between users.</li><li><strong>Centralised management</strong> — a server can store files, manage user accounts, and enforce security policies for all the devices on the network.</li><li><strong>Communication services</strong> — email, video calls and instant messaging all rely on networks.</li></ul><h2 id="_2-3-network-security" tabindex="-1">2.3 Network Security <a class="header-anchor" href="#_2-3-network-security" aria-label="Permalink to &quot;2.3 Network Security&quot;">​</a></h2><p>Security is important in network communication because data travelling across a network is vulnerable to interception, theft and tampering. Without security:</p><ul><li>Personal information (passwords, ID numbers, banking details) can be stolen and used for fraud.</li><li>Confidential business or organisational information can be leaked or sold.</li><li>Attackers can install malware on devices on the network.</li><li>The organisation&#39;s network and devices can be hijacked to attack other networks.</li></ul><h3 id="risks-of-using-public-wi-fi" tabindex="-1">Risks of using public Wi-Fi <a class="header-anchor" href="#risks-of-using-public-wi-fi" aria-label="Permalink to &quot;Risks of using public Wi-Fi&quot;">​</a></h3><p>When someone uses a public Wi-Fi network (in a coffee shop, mall, airport or hotel) to access email or any sensitive service:</p><ul><li>Data sent over the connection is often not encrypted, so an attacker on the same Wi-Fi can capture passwords and emails.</li><li>Fake &quot;hotspot&quot; networks (named to look legitimate) can be set up by criminals to harvest user data — this is called an &quot;evil twin&quot; attack.</li><li>Malware can be pushed onto the device through the open connection.</li></ul><p><strong>Precautions</strong> to reduce these risks include using a VPN to encrypt all traffic, only accessing sites that use HTTPS, turning off &quot;automatic connection to Wi-Fi&quot;, avoiding banking and sensitive logins on public networks, and using two-factor authentication on email accounts.</p><h2 id="_2-4-key-network-terms" tabindex="-1">2.4 Key Network Terms <a class="header-anchor" href="#_2-4-key-network-terms" aria-label="Permalink to &quot;2.4 Key Network Terms&quot;">​</a></h2><h3 id="ip-address" tabindex="-1">IP address <a class="header-anchor" href="#ip-address" aria-label="Permalink to &quot;IP address&quot;">​</a></h3><p>An <strong>IP address (Internet Protocol address)</strong> is a unique numerical address that identifies a device on a network. Just as every house in a street needs a unique street address so that the post office can deliver mail to the correct house, every device on a network needs a unique IP address so that data can be delivered to the correct device.</p><p>The most common form (IPv4) consists of <strong>four sets of digits separated by dots</strong>, for example <code>192.168.1.10</code>. Each of the four numbers can be between 0 and 255.</p><h3 id="bandwidth" tabindex="-1">Bandwidth <a class="header-anchor" href="#bandwidth" aria-label="Permalink to &quot;Bandwidth&quot;">​</a></h3><p><strong>Bandwidth</strong> is the maximum amount of data that can be transferred over a network connection in a given amount of time. It is typically measured in megabits per second (Mbps) or gigabits per second (Gbps). A higher bandwidth means more data can flow at the same time — like a wider road letting more cars through at once.</p><p>A connection with low bandwidth feels slow when many people try to use it at the same time, when streaming video, or when downloading large files.</p><h3 id="protocol" tabindex="-1">Protocol <a class="header-anchor" href="#protocol" aria-label="Permalink to &quot;Protocol&quot;">​</a></h3><p>A <strong>protocol</strong> is a set of rules that governs how data is transmitted and received across a network. Two devices can only communicate if they both &quot;speak&quot; the same protocol — in the same way that two people can only have a conversation if they both speak the same language. Examples include HTTP and HTTPS (for web pages), SMTP (for sending email), POP3 and IMAP (for receiving email), and FTP (for file transfer).</p><h3 id="modem" tabindex="-1">Modem <a class="header-anchor" href="#modem" aria-label="Permalink to &quot;Modem&quot;">​</a></h3><p>A <strong>modem</strong> (modulator-demodulator) is a device that converts the digital signals used by a computer into analogue signals that can travel over a telephone line, and then converts incoming analogue signals back into digital signals. Modems were essential when home internet was delivered over phone lines; today, most &quot;modems&quot; supplied by ISPs are actually combined modem-router units.</p><h2 id="_2-5-internet-safety" tabindex="-1">2.5 Internet Safety <a class="header-anchor" href="#_2-5-internet-safety" aria-label="Permalink to &quot;2.5 Internet Safety&quot;">​</a></h2><h3 id="phishing" tabindex="-1">Phishing <a class="header-anchor" href="#phishing" aria-label="Permalink to &quot;Phishing&quot;">​</a></h3><p><strong>Phishing</strong> is a type of online scam where attackers send fake emails, SMS messages or create fake websites that look like they come from a legitimate source (a bank, the school, Microsoft, etc.). The goal is to <strong>trick users into giving personal information</strong> — usernames, passwords, ID numbers, banking details — through fake login pages.</p><p>Phishing is <em>not</em> the same as illegally copying software (that is <strong>piracy</strong>) and not the same as viruses (which are malicious <em>programs</em>).</p><hr><h1 id="section-3-data-and-information-management" tabindex="-1">SECTION 3: DATA AND INFORMATION MANAGEMENT <a class="header-anchor" href="#section-3-data-and-information-management" aria-label="Permalink to &quot;SECTION 3: DATA AND INFORMATION MANAGEMENT&quot;">​</a></h1><h2 id="_3-1-units-of-data" tabindex="-1">3.1 Units of Data <a class="header-anchor" href="#_3-1-units-of-data" aria-label="Permalink to &quot;3.1 Units of Data&quot;">​</a></h2><p>The smallest unit of data in a computer is the <strong>bit</strong> (binary digit). A bit can only have one of two values: 0 or 1.</p><p>A <strong>byte</strong> consists of <strong>8 bits</strong>. Because each bit can be either 0 or 1, a single byte can represent <strong>2⁸ = 256</strong> different unique combinations. A byte is large enough to store a single character of text (a letter, a digit or a symbol) using a coding system like ASCII or Unicode.</p><p>Larger units are built up from bytes:</p><ul><li>1 kilobyte (KB) = 1 024 bytes</li><li>1 megabyte (MB) = 1 024 KB</li><li>1 gigabyte (GB) = 1 024 MB</li><li>1 terabyte (TB) = 1 024 GB</li></ul><h2 id="_3-2-number-systems" tabindex="-1">3.2 Number Systems <a class="header-anchor" href="#_3-2-number-systems" aria-label="Permalink to &quot;3.2 Number Systems&quot;">​</a></h2><p>Computers use different number systems depending on the task. The three you must know are:</p><ul><li><strong>Decimal (base 10)</strong> — the everyday system humans use, with digits 0–9.</li><li><strong>Binary (base 2)</strong> — the system computers actually use internally, with only two digits: 0 and 1.</li><li><strong>Hexadecimal (base 16)</strong> — a short-hand system used by programmers, with digits 0–9 and letters A–F (where A = 10, B = 11, C = 12, D = 13, E = 14, F = 15).</li></ul><h3 id="binary-to-decimal" tabindex="-1">Binary to Decimal <a class="header-anchor" href="#binary-to-decimal" aria-label="Permalink to &quot;Binary to Decimal&quot;">​</a></h3><p>Each position in a binary number represents a power of 2, starting from the right. Write the place values above the bits, then add up the place values where there is a 1.</p><p><strong>Example: Convert 10101100₂ to decimal</strong></p><table tabindex="0"><thead><tr><th>Place value</th><th>128</th><th>64</th><th>32</th><th>16</th><th>8</th><th>4</th><th>2</th><th>1</th></tr></thead><tbody><tr><td>Binary digit</td><td>1</td><td>0</td><td>1</td><td>0</td><td>1</td><td>1</td><td>0</td><td>0</td></tr></tbody></table><p>Add only the place values where the binary digit is 1: 128 + 32 + 8 + 4 = <strong>172</strong></p><h3 id="decimal-to-binary" tabindex="-1">Decimal to Binary <a class="header-anchor" href="#decimal-to-binary" aria-label="Permalink to &quot;Decimal to Binary&quot;">​</a></h3><p>Use the &quot;place value subtraction&quot; method or &quot;successive division by 2&quot; method.</p><p><strong>Example: Convert 198 to binary</strong></p><p>Using place value subtraction (largest power of 2 that fits, then subtract, then repeat):</p><table tabindex="0"><thead><tr><th>128</th><th>64</th><th>32</th><th>16</th><th>8</th><th>4</th><th>2</th><th>1</th></tr></thead><tbody><tr><td>1</td><td>1</td><td>0</td><td>0</td><td>0</td><td>1</td><td>1</td><td>0</td></tr></tbody></table><p>Working: 198 − 128 = 70 → 70 − 64 = 6 → 6 − 4 = 2 → 2 − 2 = 0 So we have 1s at the 128, 64, 4 and 2 positions.</p><p>Answer: <strong>11000110₂</strong></p><h3 id="hexadecimal-to-decimal" tabindex="-1">Hexadecimal to Decimal <a class="header-anchor" href="#hexadecimal-to-decimal" aria-label="Permalink to &quot;Hexadecimal to Decimal&quot;">​</a></h3><p>Each position is a power of 16, starting from the right. Multiply each digit by its place value, then add.</p><p><strong>Example: Convert 1F7₁₆ to decimal</strong></p><table tabindex="0"><thead><tr><th>Place value</th><th>256</th><th>16</th><th>1</th></tr></thead><tbody><tr><td>Hex digit</td><td>1</td><td>F (=15)</td><td>7</td></tr></tbody></table><p>(1 × 256) + (15 × 16) + (7 × 1) = 256 + 240 + 7 = <strong>503</strong></p><h3 id="decimal-to-hexadecimal" tabindex="-1">Decimal to Hexadecimal <a class="header-anchor" href="#decimal-to-hexadecimal" aria-label="Permalink to &quot;Decimal to Hexadecimal&quot;">​</a></h3><p>Successively divide by 16 and record the remainders, reading them from bottom to top.</p><p><strong>Example: Convert 289 to hexadecimal</strong></p><ul><li>289 ÷ 16 = 18 remainder 1</li><li>18 ÷ 16 = 1 remainder 2</li><li>1 ÷ 16 = 0 remainder 1</li></ul><p>Reading the remainders from bottom to top: <strong>121₁₆</strong></p><h2 id="_3-3-data-types" tabindex="-1">3.3 Data Types <a class="header-anchor" href="#_3-3-data-types" aria-label="Permalink to &quot;3.3 Data Types&quot;">​</a></h2><p>A <strong>data type</strong> tells the computer what kind of data is being stored and how much memory to reserve for it. The main primitive data types you must know are:</p><ul><li><strong>Integer</strong> — whole numbers (positive or negative) with no decimal part. Used for counting things. Example: number of items in a list, number of people in a group, age in completed years.</li><li><strong>Real / Float</strong> — numbers with a decimal part. Used for measurements and calculations that need fractions. Example: a temperature like 23.5 °C, a price like 15.95, a height in metres.</li><li><strong>Boolean</strong> — a value that can only be <strong>True</strong> or <strong>False</strong>. Used for yes/no questions. Example: &quot;Is the device connected to the internet?&quot;, &quot;Has the user accepted the terms?&quot;</li><li><strong>Char</strong> — a single character (one letter, digit or symbol). Example: &#39;K&#39;, &#39;A&#39;, &#39;7&#39;, &#39;$&#39;.</li><li><strong>String</strong> — a sequence of characters that form text. Example: &quot;Hello123&quot;, a person&#39;s name, an address.</li></ul><p>Selecting the right data type matters because the wrong choice wastes memory, can cause calculation errors (e.g. trying to do arithmetic on a string), or makes validation impossible.</p><hr><h1 id="section-4-solution-development" tabindex="-1">SECTION 4: SOLUTION DEVELOPMENT <a class="header-anchor" href="#section-4-solution-development" aria-label="Permalink to &quot;SECTION 4: SOLUTION DEVELOPMENT&quot;">​</a></h1><h2 id="_4-1-algorithms" tabindex="-1">4.1 Algorithms <a class="header-anchor" href="#_4-1-algorithms" aria-label="Permalink to &quot;4.1 Algorithms&quot;">​</a></h2><p>An <strong>algorithm</strong> is a step-by-step set of instructions that solves a particular problem or completes a particular task. A recipe is an everyday example of an algorithm. In programming, every program starts as an algorithm before any code is written.</p><h3 id="criteria-for-a-well-designed-algorithm" tabindex="-1">Criteria for a well-designed algorithm <a class="header-anchor" href="#criteria-for-a-well-designed-algorithm" aria-label="Permalink to &quot;Criteria for a well-designed algorithm&quot;">​</a></h3><p>A good algorithm must meet the following criteria:</p><ul><li><strong>Finiteness</strong> — it must always end after a finite number of steps. An algorithm must not loop forever.</li><li><strong>Definiteness</strong> — every step must be clear and unambiguous. There must be no doubt about what to do at each step.</li><li><strong>Input</strong> — it must accept zero or more clearly-defined inputs.</li><li><strong>Output</strong> — it must produce at least one clearly-defined output (the answer to the problem).</li><li><strong>Effectiveness</strong> — every step must be basic enough that it can actually be carried out.</li></ul><h3 id="order-vs-precision-in-an-algorithm" tabindex="-1">&quot;Order&quot; vs &quot;Precision&quot; in an algorithm <a class="header-anchor" href="#order-vs-precision-in-an-algorithm" aria-label="Permalink to &quot;&quot;Order&quot; vs &quot;Precision&quot; in an algorithm&quot;">​</a></h3><ul><li><strong>Order</strong> refers to the <strong>sequence</strong> of the steps — they must be carried out in the correct order. Frying an egg before cracking the shell does not work.</li><li><strong>Precision</strong> refers to <strong>how exactly</strong> each step is described — each step must be specific and unambiguous, so that the same algorithm produces the same result every time it is followed.</li></ul><h2 id="_4-2-the-ipo-table" tabindex="-1">4.2 The IPO Table <a class="header-anchor" href="#_4-2-the-ipo-table" aria-label="Permalink to &quot;4.2 The IPO Table&quot;">​</a></h2><p>An <strong>IPO (Input – Processing – Output) table</strong> is a planning tool used before writing code. It forces the programmer to think clearly about three things:</p><ul><li><strong>Input</strong> — what data the program needs from the user (or another source) to do its job.</li><li><strong>Processing</strong> — what calculations or decisions must be performed on the input.</li><li><strong>Output</strong> — what the program must show to the user as a result.</li></ul><p><strong>Example: Calculate the surface area of a sphere — formula 4 × π × r²</strong></p><table tabindex="0"><thead><tr><th>Input</th><th>Processing</th><th>Output</th></tr></thead><tbody><tr><td>The radius (r) of the sphere</td><td>Surface area = 4 × π × r × r</td><td>The surface area of the sphere</td></tr></tbody></table><h2 id="_4-3-pseudocode" tabindex="-1">4.3 Pseudocode <a class="header-anchor" href="#_4-3-pseudocode" aria-label="Permalink to &quot;4.3 Pseudocode&quot;">​</a></h2><p><strong>Pseudocode</strong> is a way of writing out an algorithm using a mixture of plain English and basic programming-style keywords (<code>IF … THEN … ELSE</code>, <code>WHILE</code>, <code>INPUT</code>, <code>OUTPUT</code>). It is not real code — it cannot be run on a computer — but its structure makes it easy to translate later into any actual programming language.</p><p><strong>Example: Profit / Loss / Break-even calculator</strong></p><p>A company makes a profit when income &gt; expenses, a loss when income &lt; expenses, and breaks even when income = expenses.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>START</span></span>
<span class="line"><span>    INPUT income</span></span>
<span class="line"><span>    INPUT expenses</span></span>
<span class="line"><span>    IF income &gt; expenses THEN</span></span>
<span class="line"><span>        OUTPUT &quot;Profit&quot;</span></span>
<span class="line"><span>    ELSE IF income &lt; expenses THEN</span></span>
<span class="line"><span>        OUTPUT &quot;Loss&quot;</span></span>
<span class="line"><span>    ELSE</span></span>
<span class="line"><span>        OUTPUT &quot;Break-even&quot;</span></span>
<span class="line"><span>    END IF</span></span>
<span class="line"><span>END</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>The pseudocode above shows three of the most important programming concepts: <strong>input</strong> (getting data from the user), <strong>selection</strong> (the IF / ELSE structure that chooses between alternatives) and <strong>output</strong> (displaying results).</p><hr><p><em>End of Grade 10 Theory Notes</em></p>`,151)])])}const m=t(s,[["render",r]]);export{p as __pageData,m as default};
